// src/app/page.tsx — Server Component (default, no directive needed)
export default async function HomePage() {
  // fetch runs on the server; the result is serialised into HTML
  const res = await fetch('https://api.example.com/posts', {
    next: { revalidate: 60 }, // ISR: refresh cached data every 60 s
  });
  const posts: Post[] = await res.json();

  return (
    <main>
      <h1>Posts</h1>
      {posts.map(p => (
        <article key={p.id}>
          <h2>{p.title}</h2>
          <p>{p.excerpt}</p>
        </article>
      ))}
    </main>
  );
}

// src/components/LikeButton.tsx — Client Component
'use client';

import { useState } from 'react';

export default function LikeButton({ initialCount }: { initialCount: number }) {
  const [count, setCount] = useState(initialCount);
  return (
    <button onClick={() => setCount(c => c + 1)}>
      ♥ {count}
    </button>
  );
}

// src/app/layout.tsx
import type { Metadata } from 'next';
import './globals.css';

export const metadata: Metadata = {
  title: 'My App',
  description: 'A Next.js application',
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

// src/app/blog/[slug]/page.tsx
import { notFound } from 'next/navigation';

interface Props {
  params: Promise<{ slug: string }>; // Next.js 15: params is a Promise
}

export default async function BlogPost({ params }: Props) {
  const { slug } = await params;
  const post = await getPost(slug);
  if (!post) notFound();

  return (
    <article>
      <h1>{post.title}</h1>
      <div dangerouslySetInnerHTML={{ __html: post.content }} />
    </article>
  );
}

// Optional: pre-render specific slugs at build time
export async function generateStaticParams() {
  const posts = await getAllPosts();
  return posts.map(p => ({ slug: p.slug }));
}

// src/app/api/users/route.ts
import { NextRequest, NextResponse } from 'next/server';

export async function GET() {
  const users = await db.user.findMany();
  return NextResponse.json(users);
}

export async function POST(req: NextRequest) {
  const body = await req.json();
  const user = await db.user.create({ data: body });
  return NextResponse.json(user, { status: 201 });
}

// src/app/contact/actions.ts
'use server';

import { revalidatePath } from 'next/cache';

export async function submitContact(formData: FormData) {
  const email = formData.get('email') as string;
  await db.contact.create({ data: { email } });
  revalidatePath('/contacts'); // purge cached page
}

// src/app/contact/ContactForm.tsx
'use client';
import { submitContact } from './actions';

export default function ContactForm() {
  return (
    <form action={submitContact}>
      <input name="email" type="email" />
      <button type="submit">Submit</button>
    </form>
  );
}

import Link from 'next/link';

export default function Nav() {
  return (
    <nav>
      <Link href="/">Home</Link>
      <Link href="/about">About</Link>
      <Link href="/blog/my-post">Post</Link>
    </nav>
  );
}

'use client';
import { useRouter } from 'next/navigation';

export default function BackButton() {
  const router = useRouter();
  return <button onClick={() => router.back()}>Go back</button>;
}

// Server Component — can use DATABASE_URL
const db = new Client(process.env.DATABASE_URL!);

// Client Component — only NEXT_PUBLIC_* is available at runtime
const base = process.env.NEXT_PUBLIC_API_BASE;

import type { NextConfig } from 'next';

const config: NextConfig = {
  // Allow <img> from these remote hostnames
  images: {
    remotePatterns: [
      { protocol: 'https', hostname: 'images.example.com' },
    ],
  },
  // Rewrite /api/v1/* to an external backend
  async rewrites() {
    return [
      { source: '/api/v1/:path*', destination: 'https://backend.example.com/:path*' },
    ];
  },
  // Redirect /old-path to /new-path
  async redirects() {
    return [
      { source: '/old-path', destination: '/new-path', permanent: true },
    ];
  },
};

export default config;

import Image from 'next/image';
import logo from '@/public/logo.png'; // static import gives w/h automatically

export default function Header() {
  return (
    <header>
      <Image src={logo} alt="Logo" priority />
      {/* Remote image — dimensions required, hostname must be in next.config */}
      <Image
        src="https://images.example.com/photo.jpg"
        alt="Photo"
        width={800}
        height={600}
      />
    </header>
  );
}

// Static metadata
export const metadata = {
  title: 'Blog | My App',
  description: 'Read the latest posts',
  openGraph: { images: ['/og/blog.png'] },
};

// Dynamic metadata from route params
export async function generateMetadata({ params }: Props) {
  const { slug } = await params;
  const post = await getPost(slug);
  return {
    title: post.title,
    description: post.excerpt,
  };
}

// Static (cached forever, SSG behaviour)
fetch(url, { cache: 'force-cache' });

// Dynamic (uncached, SSR behaviour)
fetch(url, { cache: 'no-store' });

// ISR: re-fetch after N seconds, serve stale while revalidating
fetch(url, { next: { revalidate: 60 } });

// Tag-based on-demand invalidation
fetch(url, { next: { tags: ['products'] } });
// in a Server Action:
await revalidateTag('products');

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(req: NextRequest) {
  const token = req.cookies.get('session')?.value;

  if (!token && req.nextUrl.pathname.startsWith('/dashboard')) {
    const loginUrl = new URL('/login', req.url);
    loginUrl.searchParams.set('from', req.nextUrl.pathname);
    return NextResponse.redirect(loginUrl);
  }

  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/settings/:path*'],
};
